head.script:
scwin.selectedRow = "";
scwin.userId = "";
scwin.clntNo = "";
scwin.clntNm = "";
scwin.userClsCd = "";

scwin.onpageload = function() {
	let memJson = $c.data.getMemInfo();
    console.log(memJson);
    scwin.userId = memJson.userId;
    scwin.clntNo = memJson.clntNo;
    scwin.clntNm = memJson.clntNm;
    scwin.userClsCd = memJson.userClsCd;

    scwin.f_Set("INIT");
};

scwin.f_Set = function (gubun) {
    switch ( gubun ) {    
        case "INIT" : //초기화,신규
            $c.gus.cfDisableBtnOnly([btn_Save]);
            $c.gus.cfDisableBtnOnly([udc_row]);
            ed_custcd.focus();
            break;
        case "RETRIEVE" :  //조회모드	
            $c.gus.cfEnableBtnOnly([btn_Save]);
            $c.gus.cfEnableBtnOnly([udc_row]);
            break;          
    }
}

//---------------------------------------------------------
//조회
//---------------------------------------------------------    
scwin.f_Retrieve = function () {
    //임시 107591
    if (ed_custcd.getValue() != "") {
        //tr_retrieve.Post();
        $c.sbm.execute(sbm_retrieve);
    } else {
        $c.win.alert("Customer Info is mandatory.");
        ed_custcd.focus();
    }
}

//---------------------------------------------------------
//저장
//---------------------------------------------------------  
scwin.f_Save = async function () {
    if(ds_customerPicList.getModifiedIndex().length != 0){
        if (await scwin.f_ReqFieldChk()) {
            var chk =  await $c.win.confirm("Do you wish to save?")
            if(chk){ //저장하시겠습니까?				
                //tr_save.Post(); 
                $c.sbm.execute(sbm_save);
            }
        }
    }else{
        //$c.win.alert(E_MSG_CM_ERR_001, ["Customer Pic"]); //@은(는) 변경된 사항이 없습니다.
        $c.win.alert("There have been no changes for Customer Pic");
    }  				
}    

//유효성검사
scwin.f_ReqFieldChk = async function () {   
    if (ed_custcd.getValue() == "") {
        //cfAlertMsg(E_MSG_CM_ERR_002, ["Customer Code"]);
        $c.win.alert("Customer Code is mandatory.");
        ed_custcd.focus();
        return false;
    }
    let validArray = [
        {id:"taseq", name: "담당자순번", mandatory: true, key:true}
    ];
    var chk = await $c.gus.cfValidateGrid(gr_customerPic, null, null, validArray, "CustomerPic");
    //var chk = await $c.gus.cfValidate([gr_customerPic]);
    if (!chk) {
        return false;
    }

    return true;
}

//조회조건 Clear
scwin.f_FieldClear = function () {
    ed_custcd.setValue("");
    $c.gus.cfInitObjects([ed_custnm]);
}  

//행추가
scwin.f_AddRow = function () {
    ds_customerPicList.insertRow();
    gr_customerPic.setFocusedCell(ds_customerPicList.getRowCount()-1, 0);
    ds_customerPicList.setCellData(ds_customerPicList.getRowPosition(), "code", ed_custcd.getValue());
    gr_customerPic.setFocusedCell(ds_customerPicList.getRowCount()-1, "taseq");
}

//공통팝업 열기
